sql:
SELECT instrument_name
FROM instruments
ORDER BY instrument_name;

SELECT instrument_name
FROM instruments
ORDER BY instrument_id;

SELECT instrument_id, calibration_date, calibration_result
FROM calibrations
ORDER BY calibration_date DESC;

